#include <iostream>using namespace std;int t[1000001];void add(int x,int v){    while(x<=1000000)    {        t[x]+=v;        x+=x&-x;    }}int sum(int x){    int s=0;    while(x>0)    {        s+=t[x];        x-=x&-x;    }    return s;}int find(int k){    int p=0;    for(int i=20;i>=0;i--)    {        if(p+(1<<i)<=1000000&&t[p+(1<<i)]<k)        {            k-=t[p+(1<<i)];            p+=1<<i;        }    }    return p+1;}int main(){    ios::sync_with_stdio(0);    cin.tie(0);    int n,q;    cin>>n>>q;    for(int i=0;i<n;i++)    {        int x;        cin>>x;        add(x,1);    }    while(q--)    {        int k;        cin>>k;        if(k>0)        {            add(k,1);        }        else        {            int x=find(-k);            add(x,-1);        }    }    for(int i=1;i<=1000000;i++)    {        if(sum(i)-sum(i-1)>0)        {            cout<<i;            return 0;        }    }    cout<<0;    return 0;}